for (const item of $input.all()) {
  if (item.json && item.json.output) {
    let textoLimpio = item.json.output;

    textoLimpio = textoLimpio.replace(/\*/g, '');

    textoLimpio = textoLimpio.replace(/_/g, '');

    textoLimpio = textoLimpio.replace(/#/g, '');

    item.json.output = textoLimpio;
  }
}

return $input.all();
